"use client";

import { useEffect, useRef } from "react";

export default function Visualizer({ isListening }: { isListening: boolean }) {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext("2d");
    if (!ctx) return;

    let animationId: number;
    let audioCtx: AudioContext;
    let analyser: AnalyserNode;

    const drawPlaceholder = () => {
      let phase = 0;
      const draw = () => {
        const width = canvas.clientWidth;
        const height = canvas.clientHeight;
        canvas.width = width;
        canvas.height = height;
        ctx.clearRect(0, 0, width, height);

        // Dark background
        ctx.fillStyle = "#0f0f1a";
        ctx.fillRect(0, 0, width, height);

        // Draw idle waves
        for (let i = 0; i < 32; i++) {
          let h = 15 + Math.sin(phase + i * 0.5) * 12;
          ctx.fillStyle = `rgba(0, 242, 255, 0.3)`;
          ctx.fillRect(i * (width / 32) + 2, height - h, (width / 32) - 4, h);
        }
        phase += 0.1;
        animationId = requestAnimationFrame(draw);
      };
      draw();
    };

    const drawActive = (analyserNode: AnalyserNode) => {
      const bufferLength = analyserNode.frequencyBinCount;
      const dataArray = new Uint8Array(bufferLength);

      const draw = () => {
        const width = canvas.clientWidth;
        const height = canvas.clientHeight;
        canvas.width = width;
        canvas.height = height;

        analyserNode.getByteFrequencyData(dataArray);
        ctx.clearRect(0, 0, width, height);
        
        ctx.fillStyle = "#0f0f1a";
        ctx.fillRect(0, 0, width, height);

        const barWidth = (width / bufferLength) * 1.8;
        let x = 0;
        for (let i = 0; i < bufferLength; i++) {
          let barHeight = (dataArray[i] / 255) * height * 0.9;
          if (barHeight < 2) barHeight = 2;
          
          const intensity = dataArray[i] / 255;
          const r = 0 + Math.floor(112 * intensity);
          const g = 150 + Math.floor(105 * intensity);
          const b = 255;
          
          ctx.fillStyle = `rgba(${r}, ${g}, ${b}, 0.85)`;
          ctx.fillRect(x, height - barHeight, Math.max(barWidth - 1, 2), barHeight);
          x += barWidth;
        }
        animationId = requestAnimationFrame(draw);
      };
      draw();
    };

    const startAudio = async () => {
      try {
        const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
        audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)();
        analyser = audioCtx.createAnalyser();
        analyser.fftSize = 128;
        const source = audioCtx.createMediaStreamSource(stream);
        source.connect(analyser);
        drawActive(analyser);
      } catch (e) {
        drawPlaceholder(); // Fallback to placeholder if no mic
      }
    };

    if (isListening) {
      startAudio();
    } else {
      drawPlaceholder();
    }

    return () => {
      cancelAnimationFrame(animationId);
      if (audioCtx) audioCtx.close();
    };
  }, [isListening]);

  return (
    <div className="glass-panel p-5">
      <div className="flex justify-between items-center mb-3">
        <span className="text-xs font-mono text-cyan-300 tracking-wider">◢ AUDIO SPECTRUM</span>
      </div>
      <canvas ref={canvasRef} className="w-full h-[110px] rounded-[40px] drop-shadow-[0_0_6px_cyan]" />
    </div>
  );
}
