"use client";

import { useSpeechRecognition } from "@/hooks/useSpeechRecognition";

interface VoiceControlProps {
  onCommand: (command: string) => void;
  statusText: string;
}

export default function VoiceControl({ onCommand, statusText }: VoiceControlProps) {
  const { isListening, error, startListening, stopListening, hasSupport } = useSpeechRecognition((transcript) => {
    onCommand(transcript);
  });

  const toggleListen = () => {
    if (isListening) stopListening();
    else startListening();
  };

  if (!hasSupport) {
    return (
      <div className="glass-panel p-5 flex flex-col items-center bg-[#0c0c1c]/50 backdrop-blur-xl border border-cyan-400/20 rounded-3xl">
        <p className="text-red-400 text-sm">Trình duyệt của bạn không hỗ trợ nhận diện giọng nói.</p>
      </div>
    );
  }

  return (
    <div className="glass-panel p-5 flex flex-col items-center">
      <div className={`relative w-28 h-28 md:w-32 md:h-32 ${isListening ? 'listening' : ''}`}>
        <button 
          onClick={toggleListen}
          className="mic-btn w-full h-full rounded-full flex items-center justify-center focus:outline-none"
        >
          <svg xmlns="http://www.w3.org/2000/svg" className="h-12 w-12 text-white drop-shadow-lg" viewBox="0 0 20 20" fill="currentColor">
              <path fillRule="evenodd" d="M7 4a3 3 0 016 0v4a3 3 0 11-6 0V4zm4 10.93A7.001 7.001 0 0017 8a1 1 0 10-2 0A5 5 0 015 8a1 1 0 00-2 0 7.001 7.001 0 006 6.93V17H6a1 1 0 100 2h8a1 1 0 100-2h-3v-2.07z" clipRule="evenodd" />
          </svg>
        </button>
      </div>
      <div className="mt-4 text-center text-sm font-mono text-cyan-300 bg-black/30 py-2 px-4 rounded-full backdrop-blur-sm w-full">
        <span>{error ? `⚠️ ${error}` : isListening ? "🎤 Đang nghe... hãy nói lệnh" : statusText}</span>
      </div>
    </div>
  );
}
